/** List of locales that Chrome compact ICU does not fully support. */
const FALLBACK_LOCALES = new Set(["ka","vi","zu","is"]);

/**
 * Get localized region (country) label with fallback for Chrome ICU gaps.
 * @param code  ISO 3166-1 alpha-2 code (e.g. "RS")
 * @param locale Current UI locale (e.g. "ka")
 * @param displayNames Intl.DisplayNames instance for the current locale
 */
export function getLocalizedRegionLabel(
  code: string,
  locale: string,
  displayNames: Intl.DisplayNames | null,
): string {
  const upper = code.trim().toUpperCase();
  if (FALLBACK_LOCALES.has(locale)) {
    const fb = ICU_FALLBACK[locale]?.regions[upper];
    if (fb) return fb;
  }
  const localized = displayNames?.of(upper);
  return localized && localized !== upper ? localized : upper;
}

/**
 * Get localized language label with fallback for Chrome ICU gaps.
 * @param code  BCP 47 language code (e.g. "sr")
 * @param locale Current UI locale (e.g. "ka")
 * @param displayNames Intl.DisplayNames instance for the current locale
 */
// Script subtags to strip for cleaner display (e.g. "sr-Latn" → "sr" → "Serbian" not "Serbian (Latin)")
const STRIP_SCRIPT_FOR_DISPLAY: Record<string, string> = {
  "sr-latn": "sr",
};

export function getLocalizedLanguageLabel(
  code: string,
  locale: string,
  displayNames: Intl.DisplayNames | null,
): string {
  const lower = code.trim().toLowerCase();
  if (FALLBACK_LOCALES.has(locale)) {
    const fb = ICU_FALLBACK[locale]?.languages[lower];
    if (fb) return fb;
  }
  const lookupCode = STRIP_SCRIPT_FOR_DISPLAY[lower] ?? lower;
  const localized = displayNames?.of(lookupCode);
  return localized && localized !== lookupCode ? localized : code;
}
